/**
 * Registry for cyclomatic complexity providers.
 *
 * Each provider handles specific languages. The registry selects the right provider
 * for a given language, falling back to the built-in estimator.
 */

import type { CyclomaticComplexityProvider, CcResult, DocumentInfo } from "./ports";

/** A CC provider that covers one or more languages. */
export type LanguageCcProvider = {
  readonly supportedLanguages: readonly string[];
  readonly provider: CyclomaticComplexityProvider;
};

/** Fallback provider that works offline for all languages via regex-based estimation. */
export class FallbackCcProvider implements CyclomaticComplexityProvider {
  async computeComplexity(_doc: DocumentInfo): Promise<CcResult> {
    // The fallback only provides per-symbol estimation, not per-document.
    // It returns empty maps; the orchestrator uses estimateCyclomaticComplexity per symbol body.
    return { byLine: new Map(), byName: new Map() };
  }
}

export class CcProviderRegistry {
  private readonly providers = new Map<string, CyclomaticComplexityProvider>();
  private readonly fallback: CyclomaticComplexityProvider = new FallbackCcProvider();

  register(entry: LanguageCcProvider): void {
    for (const lang of entry.supportedLanguages) {
      this.providers.set(lang, entry.provider);
    }
  }

  getForLanguage(languageId: string): CyclomaticComplexityProvider {
    return this.providers.get(languageId) ?? this.fallback;
  }
}

src/core/churn.ts.source:
import type { SymbolMetrics } from "./analyze";

/** Returns G ≥ 1. Log-scaled so high-churn outliers don't dominate. */
export function churnMultiplier(commitCount: number): number {
  return 1 + Math.log1p(commitCount);
}

/** Returns a new array of symbols with g and fPrime set from the commit counts map.
 *  Symbols whose URI is absent from the map are unchanged (g=1, fPrime=f). */
export function applyChurn(
  symbols: readonly SymbolMetrics[],
  counts: Map<string, number>
): SymbolMetrics[] {
  return symbols.map((s) => {
    const count = counts.get(s.uri);
    if (count === undefined) return { ...s };
    const g = churnMultiplier(count);
    return { ...s, g, fPrime: s.f * g };
  });
}

src/core/churnParse.ts.source:
/**
 * Parses the stdout of:
 *   git log --name-only --pretty=format: --since=<date>
 * and returns a map of relative file path → commit count.
 */
export function parseGitLogToChurnCounts(stdout: string): Map<string, number> {
  const counts = new Map<string, number>();
  for (const line of stdout.split("\n")) {
    const path = line.trim();
    if (path) {
      counts.set(path, (counts.get(path) ?? 0) + 1);
    }
  }
  return counts;
}

src/core/coverageMap.ts.source:
/**
 * Map statement-level coverage onto a symbol body line range (0-based lines).
 */

import { clamp01 } from "./metrics";

/** A range of line numbers (0-based, inclusive). */
export type LineRange = {
  readonly startLine: number;
  readonly endLine: number;
};

/** A single statement coverage record from LCOV or similar. */
export type StatementCover = {
  readonly executed: boolean;
  readonly startLine: number;
  readonly endLine: number;
};

function overlaps(a: LineRange, b: LineRange): boolean {
  return a.startLine <= b.endLine && b.startLine <= a.endLine;
}

/**
 * Compute test coverage fraction T for a symbol body.
 *
 * @param body       The line range of the function/method body (0-based).
 * @param statements Statement coverage records for the file.
 * @param fallbackT  Coverage to use when no statements overlap the body.
 * @returns T in [0, 1]: executedStatements / totalStatements within body.
 */
export function coverageFractionForSymbol(
  body: LineRange,
  statements: readonly StatementCover[],
  fallbackT: number
): number {
  let total = 0;
  let covered = 0;
  for (const s of statements) {
    const sr: LineRange = { startLine: s.startLine, endLine: s.endLine };
    if (!overlaps(body, sr)) {
      continue;
    }
    total += 1;
    if (s.executed) {
      covered += 1;
    }
  }
  if (total === 0) {
    return clamp01(fallbackT);
  }
  return covered / total;
}

src/core/coverageStore.ts.source:
import type { StatementCover } from "./coverageMap";

/**
 * Holds statement-level coverage keyed by file URI string.
 * No VS Code dependency — testable with vitest.
 */
export class CoverageStore {
  private readonly byUri = new Map<string, StatementCover[]>();

  clear(): void {
    this.byUri.clear();
  }

  get(uri: string): StatementCover[] | undefined {
    // Try exact match first
    const result = this.byUri.get(uri);
    if (result) {
      return result;
    }

    // On Windows, try case-insensitive match as fallback
    // URI strings may have different encoding between different code paths
    if (process.platform === "win32") {
      const keyLower = uri.toLowerCase();
      for (const [storedKey, statements] of this.byUri) {
        if (storedKey.toLowerCase() === keyLower) {
          return statements;
        }
      }
    }

    return undefined;
  }

  /** Store statement coverage records for a file URI. */
  ingestStatementCovers(uriString: string, statements: readonly StatementCover[]): void {
    this.byUri.set(uriString, [...statements]);
  }
}

