/**
 * Lightweight cyclomatic-complexity estimate from source text (McCabe-style decision count + 1).
 * Prefer language-specific tools when configured; this works offline for all languages.
 */

const KEYWORD_DECISIONS = ["while", "for", "foreach", "case", "catch"];

function countDecisions(source: string): number {
  let count = 0;

  // Count keyword-based decisions via word boundaries
  for (const kw of KEYWORD_DECISIONS) {
    const pattern = new RegExp(String.raw`\b${kw}\b`, "g");
    while (pattern.exec(source) !== null) {
      count += 1;
    }
  }

  // Count `if` that is NOT preceded by `else` (standalone if)
  // and `else if` as a single decision each
  const ifPattern = /\b(else\s+)?if\b/g;
  while (ifPattern.exec(source) !== null) {
    count += 1;
  }

  // Count logical operators && and ||
  const logicalPattern = /&&|\|\|/g;
  while (logicalPattern.exec(source) !== null) {
    count += 1;
  }

  // Count ternary expressions: ? <expr> :
  const ternaryPattern = /\?\s*[^;?:]+:/g;
  while (ternaryPattern.exec(source) !== null) {
    count += 1;
  }

  return count;
}

export function estimateCyclomaticComplexity(source: string): number {
  return Math.max(1, 1 + countDecisions(source));
}

src/core/graphBuilder.ts.source:
import type { CallEdge } from "./rank";

/** One caller and its callees (e.g. from LSP outgoing calls). */
export type CallerCallees = {
  readonly callerId: string;
  readonly calleeIds: readonly string[];
};

/**
 * Convert caller-callee groups into flat call edges, filtering self-edges.
 *
 * @param rows Each row represents one caller and its outgoing callees.
 * @returns Flat list of { caller, callee } edges with self-edges removed.
 */
export function edgesFromCallerCallees(rows: readonly CallerCallees[]): CallEdge[] {
  const edges: CallEdge[] = [];
  for (const row of rows) {
    for (const callee of row.calleeIds) {
      if (callee !== row.callerId) {
        edges.push({ caller: row.callerId, callee });
      }
    }
  }
  return edges;
}

src/core/jacocoParse.ts.source:
import type { StatementCover } from "./coverageMap";

/**
 * Minimal JaCoCo XML parser — extracts line-level coverage from <sourcefile> elements.
 *
 * JaCoCo XML structure (relevant parts):
 *   <report>
 *     <package name="com/example">
 *       <sourcefile name="Foo.java">
 *         <line nr="10" mi="0" ci="3" mb="0" cb="0"/>
 *       </sourcefile>
 *     </package>
 *   </report>
 *
 * Line numbers in JaCoCo are 1-based; we emit 0-based for core/coverageMap.
 * A line is "executed" when ci (covered instructions) > 0.
 * File key: "packageName/sourceFileName" (e.g. "com/example/Foo.java").
 */
export function parseJacocoToStatementCovers(xml: string): Map<string, StatementCover[]> {
  const byFile = new Map<string, StatementCover[]>();
  const packageRe = /<package\s+name="([^"]*)"[^>]*>/g;
  const sourcefileRe = /<sourcefile\s+name="([^"]*)"[^>]*>([\s\S]*?)<\/sourcefile>/g;
  // NB: assumes JaCoCo's fixed attribute order (nr, mi, ci) — safe for generated XML.
  const lineRe = /<line\s+nr="(\d+)"\s+mi="(\d+)"\s+ci="(\d+)"[^/]*\/>/g;

  let pkgMatch: RegExpExecArray | null;
  while ((pkgMatch = packageRe.exec(xml)) !== null) {
    const pkgName = pkgMatch[1];
    const pkgStart = pkgMatch.index;
    // Find the end of this package element
    const pkgEndIdx = xml.indexOf("</package>", pkgStart);
    const pkgBody = pkgEndIdx > pkgStart ? xml.slice(pkgStart, pkgEndIdx) : xml.slice(pkgStart);

    let sfMatch: RegExpExecArray | null;
    sourcefileRe.lastIndex = 0;
    while ((sfMatch = sourcefileRe.exec(pkgBody)) !== null) {
      const sfName = sfMatch[1];
      const sfBody = sfMatch[2];
      const fileKey = pkgName ? `${pkgName}/${sfName}` : sfName;

      const stmts: StatementCover[] = [];
      let lineMatch: RegExpExecArray | null;
      lineRe.lastIndex = 0;
      while ((lineMatch = lineRe.exec(sfBody)) !== null) {
        const nr = parseInt(lineMatch[1], 10);
        const ci = parseInt(lineMatch[3], 10);
        if (Number.isNaN(nr) || Number.isNaN(ci) || nr < 1) {
          continue;
        }
        stmts.push({
          executed: ci > 0,
          startLine: nr - 1,
          endLine: nr - 1,
        });
      }

      if (stmts.length > 0) {
        byFile.set(fileKey, stmts);
      }
    }
  }

  return byFile;
}

