  // ═════════════════════════════════════════════════════════════════════
  // bugmagnet session 2026-04-16
  // ═════════════════════════════════════════════════════════════════════
  describe("bugmagnet session 2026-04-16", () => {
    // ─── complex interactions ──────────────────────────────────────────
    describe("complex interactions", () => {
      it("returns empty then lenses when config toggles from disabled to enabled", async () => {
