      it("returns correct lenses when called with different documents sequentially", async () => {
        const m1 = sym({ id: "id-doc1" });
        const m2 = sym({ id: "id-doc2" });
        const provider = new DdpCodeLensProvider(fakeState([m1, m2]), () => fakeConfig());

        // First document
