        // Second document
        const doc2 = fakeDocument("file:///doc2.ts");
        vi.mocked(getFlatFunctionSymbols).mockResolvedValue([fakeSymbol("fn2", 5, 0)]);
        vi.mocked(symbolIdFromUriRange).mockReturnValue("id-doc2");
